// Copyright 2016 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.// Binary package export.// This file was derived from $GOROOT/src/cmd/compile/internal/gc/bexport.go;// see that file for specification of the format.package gcimporterimport ("bytes""encoding/binary""fmt""go/constant""go/token""go/types""math""math/big""sort""strings")// If debugFormat is set, each integer and string value is preceded by a marker// and position information in the encoding. This mechanism permits an importer// to recognize immediately when it is out of sync. The importer recognizes this// mode automatically (i.e., it can import export data produced with debugging// support even if debugFormat is not set at the time of import). This mode will// lead to massively larger export data (by a factor of 2 to 3) and should only// be enabled during development and debugging.//// NOTE: This flag is the first flag to enable if importing dies because of// (suspected) format errors, and whenever a change is made to the format.const debugFormat = false // default: false// Current export format version. Increase with each format change.//// Note: The latest binary (non-indexed) export format is at version 6.// This exporter is still at level 4, but it doesn't matter since// the binary importer can handle older versions just fine.////6: package height (CL 105038) -- NOT IMPLEMENTED HERE//5: improved position encoding efficiency (issue 20080, CL 41619) -- NOT IMPLEMENTED HERE//4: type name objects support type aliases, uses aliasTag//3: Go1.8 encoding (same as version 2, aliasTag defined but never used)//2: removed unused bool in ODCL export (compiler only)//1: header format change (more regular), export package for _ struct fields//0: Go1.7 encodingconst exportVersion = 4// trackAllTypes enables cycle tracking for all types, not just named// types. The existing compiler invariants assume that unnamed types// that are not completely set up are not used, or else there are spurious// errors.// If disabled, only named types are tracked, possibly leading to slightly// less efficient encoding in rare cases. It also prevents the export of// some corner-case type declarations (but those are not handled correctly// with with the textual export format either).// TODO(gri) enable and remove once issues caused by it are fixedconst trackAllTypes = falsetype exporter struct {fset *token.FileSetout  bytes.Buffer// object -> index maps, indexed in order of serializationstrIndex map[string]intpkgIndex map[*types.Package]inttypIndex map[types.Type]int// position encodingposInfoFormat boolprevFile      stringprevLine      int// debugging supportwritten int // bytes writtenindent  int // for trace}// internalError represents an error generated inside this package.type internalError string (e internalError) Error() string { return "gcimporter: " + string(e) } internalErrorf(format string, args ...interface{}) error {return internalError(fmt.Sprintf(format, args...))}ExportData returns binary export data for pkg.// If no file set is provided, position info will be missing. BExportData(fset *token.FileSet, pkg *types.Package) (b []byte, err error) {if !debug {defer () {if e := recover(); e != nil {if ierr, ok := e.(internalError); ok {err = ierrreturn}// Not an internal error; panic again.panic(e)}}()}p := exporter{fset:          fset,strIndex:      map[string]int{"": 0}, // empty string is mapped to 0pkgIndex:      make(map[*types.Package]int),typIndex:      make(map[types.Type]int),posInfoFormat: true, // TODO(gri) might become a flag, eventually}// write version info// The version string must start with "version %d" where %d is the version// number. Additional debugging information may follow after a blank; that// text is ignored by the importer.p.rawStringln(fmt.Sprintf("version %d", exportVersion))var debug stringif debugFormat {debug = "debug"}p.rawStringln(debug) // cannot use p.bool since it's affected by debugFormat; also want to see this clearlyp.bool(trackAllTypes)p.bool(p.posInfoFormat)// --- generic export data ---// populate type map with predeclared "known" typesfor index, typ := range predeclared() {p.typIndex[typ] = index}if len(p.typIndex) != len(predeclared()) {return nil, internalError("duplicate entries in type map?")}// write package datap.pkg(pkg, true)if trace {p.tracef("\n")}// write objectsobjcount := 0scope := pkg.Scope()for _, name := range scope.Names() {if !token.IsExported(name) {continue}if trace {p.tracef("\n")}p.obj(scope.Lookup(name))objcount++}// indicate end of listif trace {p.tracef("\n")}p.tag(endTag)// for self-verification only (redundant)p.int(objcount)if trace {p.tracef("\n")}// --- end of export data ---return p.out.Bytes(), nil} (p *exporter) pkg(pkg *types.Package, emptypath bool) {if pkg == nil {panic(internalError("unexpected nil pkg"))}// if we saw the package before, write its index (>= 0)if i, ok := p.pkgIndex[pkg]; ok {p.index('P', i)return}// otherwise, remember the package, write the package tag (< 0) and package dataif trace {p.tracef("P%d = { ", len(p.pkgIndex))defer p.tracef("} ")}p.pkgIndex[pkg] = len(p.pkgIndex)p.tag(packageTag)p.string(pkg.Name())if emptypath {p.string("")lse {p.string(pkg.Path())}} (p *exporter) obj(obj types.Object) {switch obj := obj.(type) {case *types.Const:p.tag(constTag)p.pos(obj)p.qualifiedName(obj)p.typ(obj.Type())p.value(obj.Val())case *types.TypeName:if obj.IsAlias() {p.tag(aliasTag)p.pos(obj)p.qualifiedName(obj)} else {p.tag(typeTag)}p.typ(obj.Type())case *types.p.tag(ag)p.pos(obj)p.qualifiedName(obj)p.typ(obj.Type())case *types.:p.tag(Tag)p.pos(obj)p.qualifiedName(obj)sig := obj.Type().(*types.Signature)paramList(sig.Params(), sig.Variadic())p.paramList(sig.Results(), false)default:panic(internalErrorf("unexpected object %v (%T)", obj, obj))}} (p *exporter) pos(obj types.Object) {if !p.posInfoFormat {return}file, line := p.fileLine(obj)if file == p.prevFile {// common